#!/usr/bin/env bash
#
# certify.sh - shared qualification runner
#
# Invoked by per-target wrapper scripts generated by the flake.  The wrapper
# exports TARGET_* env vars describing the simulator target, then execs this
# script.  This script dispatches on $TARGET_ADAPTER to run the test suite
# and produce a standard set of qualification artefacts.
#
# Required env vars (all targets):
#   TARGET_NAME          registry key (e.g. quartus-25.1-sim-only-qrun)
#   TARGET_ADAPTER       "container" | "native" | "fhs"
#   TARGET_DISPLAY_NAME  human-readable
#   TARGET_TOOL          simulator tool name (qrun|modelsim|verilator|xsim)
#   TARGET_PYTEST_FILTER pytest -k expression
#   TOOL_GROUP, TOOL_VERSION, QUALIFIED_VERSION  qualification identifiers
#   ARTEFACTS_ROOT       parent dir to write run-id subdir into
#   CERT_TOOLS_DIR       path to qualification-helpers.sh host dir
#   TIMING_SUMMARY_SCRIPT  nix store path to timing-summary.py
#
# Container adapter extras:
#   TARGET_IMAGE, TARGET_INSTALL_ROOT, TARGET_CONTAINER_PATH,
#   TARGET_EXPECTED_QUARTUS ("" to skip), TARGET_EXPECTED_QUESTA,
#   TARGET_HAS_QUARTUS_SH (0|1), LICENSE_DIR, CONTAINER_RUNTIME
#
# Native adapter extras:
#   TARGET_EXPECTED_VERILATOR, TARGET_VERILATOR_STORE_PATH
#
# FHS adapter extras:
#   TARGET_EXPECTED_VIVADO, TARGET_VIVADO_PROFILE,
#   TARGET_VIVADO_STORE_PATH, TARGET_VIVADO_IS_STUB, TARGET_QUALIFIED_ROOT

set -euo pipefail

# shellcheck source=/dev/null
source "${CERT_TOOLS_DIR}/scripts/qualification-helpers.sh"

OUTPUT_DIR=""
PYTEST_FILTER_OVERRIDE=""
REUSE_BUILD=0
SIM_DEBUG_LEVEL=""
SIM_RUNTIME_STATS=0
XSIM_RUN_MODE=""
REPO_ROOT="${REPO_ROOT:-$(pwd)}"

usage() {
  cat <<EOF
Usage: svunit-certify-${TARGET_NAME} [--output-dir DIR] [--filter EXPR] [--reuse-build] [--xsim-reuse-build] [--sim-debug-level LEVEL] [--sim-runtime-stats] [--xsim-run-mode MODE]

Target:  ${TARGET_NAME}
Adapter: ${TARGET_ADAPTER}
Display: ${TARGET_DISPLAY_NAME}

Options:
  --output-dir DIR       Override artefact output dir (default: per qualification standard)
  --filter EXPR          Override pytest -k filter (default: ${TARGET_PYTEST_FILTER})
  --reuse-build          Experimental qrun/modelsim/xsim mode; reuse unchanged build artefacts
  --xsim-reuse-build     Backward-compatible xsim-only alias for --reuse-build
  --sim-debug-level LVL  Forward normalized debug level to runSVUnit
  --sim-runtime-stats    Forward normalized runtime-statistics request to runSVUnit
  --xsim-run-mode MODE   Forward xsim run mode to runSVUnit (separate or standalone)
EOF
  exit 2
}

while [ $# -gt 0 ]; do
  case "$1" in
    --output-dir|-o) OUTPUT_DIR="$2"; shift 2 ;;
    --filter|-k)     PYTEST_FILTER_OVERRIDE="$2"; shift 2 ;;
    --reuse-build) REUSE_BUILD=1; shift ;;
    --sim-debug-level)
      SIM_DEBUG_LEVEL="$2"
      shift 2
      ;;
    --xsim-reuse-build)
      if [ "${TARGET_TOOL}" != "xsim" ]; then
        echo "ERROR: --xsim-reuse-build is only supported for xsim targets." >&2
        exit 2
      fi
      REUSE_BUILD=1
      shift
      ;;
    --sim-runtime-stats) SIM_RUNTIME_STATS=1; shift ;;
    --xsim-run-mode)
      XSIM_RUN_MODE="$2"
      shift 2
      ;;
    --help|-h)       usage ;;
    *) echo "Unknown argument: $1" >&2; usage ;;
  esac
done

PYTEST_FILTER="${PYTEST_FILTER_OVERRIDE:-${TARGET_PYTEST_FILTER}}"
PER_FIXTURE_PYTEST_FILTER="(${PYTEST_FILTER}) and not profile_compile_once"
COMPILE_ONCE_PYTEST_FILTER="(${PYTEST_FILTER}) and profile_compile_once"
SIM_DEBUG_LEVEL="${SIM_DEBUG_LEVEL,,}"
XSIM_RUN_MODE="${XSIM_RUN_MODE,,}"

if [ "${REUSE_BUILD}" = "1" ] &&
   [ "${TARGET_TOOL}" != "qrun" ] &&
   [ "${TARGET_TOOL}" != "modelsim" ] &&
   [ "${TARGET_TOOL}" != "xsim" ]; then
  echo "ERROR: --reuse-build is only supported for qrun, modelsim, and xsim targets." >&2
  exit 2
fi

case "${SIM_DEBUG_LEVEL}" in
  ""|none|low|medium|med|high|all) ;;
  *)
    echo "ERROR: --sim-debug-level must be one of none, low, medium, med, high, or all." >&2
    exit 2
    ;;
esac

case "${XSIM_RUN_MODE}" in
  ""|separate|standalone) ;;
  *)
    echo "ERROR: --xsim-run-mode must be one of separate or standalone." >&2
    exit 2
    ;;
esac

if [ "${XSIM_RUN_MODE}" = "standalone" ] && [ "${TARGET_TOOL}" != "xsim" ]; then
  echo "ERROR: --xsim-run-mode standalone is only supported for xsim targets." >&2
  exit 2
fi

setup_tool_timing_wrappers() {
  local timing_dir="$1"
  shift

  local wrapper_bin="${timing_dir}/bin"
  local timing_log="${timing_dir}/tool-invocations.tsv"
  mkdir -p "${wrapper_bin}"
  printf 'start_utc\ttool\tduration_ms\texit_code\tcwd\targs\tprofile_mode\tend_utc\tstart_epoch_ms\tend_epoch_ms\tpid\n' > "${timing_log}"

  local tool real_tool wrapper
  for tool in "$@"; do
    real_tool="$(command -v "$tool" 2>/dev/null || true)"
    if [ -z "${real_tool}" ]; then
      continue
    fi
    wrapper="${wrapper_bin}/${tool}"
    {
      printf '#!/usr/bin/env bash\n'
      printf 'set -uo pipefail\n'
      printf 'real_tool=%q\n' "${real_tool}"
      printf 'tool_name=%q\n' "${tool}"
      printf 'timing_log=%q\n' "${timing_log}"
      cat <<'WRAP_EOF'
start_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
start_ns="$(date +%s%N)"
start_epoch_ms=$(( start_ns / 1000000 ))
pid="${BASHPID:-$$}"
"${real_tool}" "$@"
rc=$?
end_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
end_ns="$(date +%s%N)"
end_epoch_ms=$(( end_ns / 1000000 ))
duration_ms=$(( (end_ns - start_ns) / 1000000 ))
args=()
for arg in "$@"; do
  args+=("$(printf '%q' "$arg")")
done
printf '%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\n' \
  "$start_utc" "$tool_name" "$duration_ms" "$rc" "$PWD" "${args[*]}" \
  "${SVUNIT_PROFILE_MODE:-unknown}" "$end_utc" "$start_epoch_ms" \
  "$end_epoch_ms" "$pid" \
  >> "$timing_log"
exit "$rc"
WRAP_EOF
    } > "${wrapper}"
    chmod +x "${wrapper}"
  done

  export PATH="${wrapper_bin}:${PATH}"
}

write_tool_timing_summary() {
  local timing_dir="$1"
  local timing_log="${timing_dir}/tool-invocations.tsv"

  [ -f "${timing_log}" ] || return 0

  awk -F '\t' '
    BEGIN {
      OFS = "\t"
      print "profile_mode", "tool", "count", "total_ms", "avg_ms", "max_ms"
    }
    NR > 1 {
      duration_ms = $3 + 0
      key = $7 SUBSEP $2
      if (!(key in seen)) {
        seen[key] = 1
        keys[++n] = key
        profile_mode[key] = $7
        tool[key] = $2
      }
      count[key] += 1
      total_ms[key] += duration_ms
      if (duration_ms > max_ms[key]) {
        max_ms[key] = duration_ms
      }
    }
    END {
      for (i = 1; i <= n; i++) {
        key = keys[i]
        avg_ms = count[key] ? total_ms[key] / count[key] : 0
        printf "%s\t%s\t%d\t%.0f\t%.1f\t%.0f\n",
          profile_mode[key], tool[key], count[key], total_ms[key], avg_ms, max_ms[key]
      }
    }
  ' "${timing_log}" > "${timing_dir}/tool-summary.tsv"

  awk -F '\t' '
    BEGIN {
      OFS = "\t"
      print "profile_mode", "cwd", "tool", "count", "total_ms", "avg_ms", "max_ms"
    }
    NR > 1 {
      duration_ms = $3 + 0
      key = $7 SUBSEP $5 SUBSEP $2
      if (!(key in seen)) {
        seen[key] = 1
        keys[++n] = key
        profile_mode[key] = $7
        cwd[key] = $5
        tool[key] = $2
      }
      count[key] += 1
      total_ms[key] += duration_ms
      if (duration_ms > max_ms[key]) {
        max_ms[key] = duration_ms
      }
    }
    END {
      for (i = 1; i <= n; i++) {
        key = keys[i]
        avg_ms = count[key] ? total_ms[key] / count[key] : 0
        printf "%s\t%s\t%s\t%d\t%.0f\t%.1f\t%.0f\n",
          profile_mode[key], cwd[key], tool[key], count[key], total_ms[key], avg_ms, max_ms[key]
      }
    }
  ' "${timing_log}" > "${timing_dir}/tool-by-cwd.tsv"

  echo "Wrote tool timing summaries in ${timing_dir}"
}

run_profile_pytest() {
  local mode="$1"
  local filter="$2"
  local xml="$3"
  local start_utc start_ns end_utc end_ns duration_ms pytest_rc

  echo ""
  start_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
  start_ns="$(date +%s%N)"
  echo "--- pytest ${mode} -k ${filter} start=${start_utc} ---"
  set +e
  SVUNIT_PROFILE_MODE="${mode}" \
    SVUNIT_REUSE_BUILD="${REUSE_BUILD}" \
    SVUNIT_XSIM_REUSE_BUILD="$([ "${TARGET_TOOL}" = "xsim" ] && echo "${REUSE_BUILD}" || echo 0)" \
    SVUNIT_SIM_DEBUG_LEVEL="${SIM_DEBUG_LEVEL}" \
    SVUNIT_SIM_RUNTIME_STATS="${SIM_RUNTIME_STATS}" \
    SVUNIT_XSIM_RUN_MODE="${XSIM_RUN_MODE}" \
    python3 -m pytest -v -k "${filter}" \
    --tb=short \
    --basetemp="${OUTPUT_DIR}/pytest-${mode}" \
    --durations=0 \
    --junitxml="${xml}" \
    2>&1
  pytest_rc=$?
  set -e
  end_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
  end_ns="$(date +%s%N)"
  duration_ms=$(( (end_ns - start_ns) / 1000000 ))
  echo "--- pytest ${mode} end=${end_utc} duration_ms=${duration_ms} exit_code=${pytest_rc} ---"
}

write_sim_runtime_stats_summary() {
  local output_dir="$1"
  local log="${output_dir}/test-log.txt"
  local tsv="${output_dir}/sim-runtime-stats.tsv"
  local json="${output_dir}/sim-runtime-stats.json"

  [ -f "${log}" ] || return 0

  SVUNIT_CERTIFY_SIM_RUNTIME_STATS="${SIM_RUNTIME_STATS:-0}" \
    python3 - "${output_dir}" "${log}" "${tsv}" "${json}" <<'PY'
import glob
import json
import os
import re
import sys

output_dir, log_path, tsv_path, json_path = sys.argv[1:5]
mode = "unknown"
entries = []
seen_sources = set()
runtime_stats_enabled = os.environ.get("SVUNIT_CERTIFY_SIM_RUNTIME_STATS") == "1"

mode_start_re = re.compile(r"^--- pytest ([^ ]+) .* start=")
xsim_re = re.compile(
    r"xsimkernel Simulation Memory Usage:\s+(\d+)\s+KB "
    r"\(Peak:\s+(\d+)\s+KB\), Simulation CPU Usage:\s+(\d+)\s+ms"
)
questa_stats_arg_re = re.compile(r"(?:^|\s)-(?:printsimstats|stats(?:=\S+)?)\b", re.I)
questa_tool_re = re.compile(r"^(vlog|vopt|vsim)\b", re.I)
questa_memory_re = re.compile(
    r"mem:\s+(.+?)\s+([0-9]+(?:\.[0-9]+)?)\s+([kmg]b)\b",
    re.I,
)
questa_time_re = re.compile(
    r"(vopt|elab|sim|total|license):\s+(.+?)\s+"
    r"([0-9]+(?:\.[0-9]+)?)\s+s\b",
    re.I,
)
hdl_time_re = re.compile(r"HDL Simulation time\s+(.+)$", re.I)
end_time_re = re.compile(r"End time:.*Elapsed time:\s+([0-9:]+)", re.I)
verilator_wall_re = re.compile(
    r"^- Verilator:\s+\$finish .*?walltime\s+([0-9]+(?:\.[0-9]+)?)\s+s;",
    re.I,
)
verilator_cpu_re = re.compile(
    r"^- Verilator:\s+cpu\s+([0-9]+(?:\.[0-9]+)?)\s+s on "
    r"([0-9]+)\s+threads; alloced\s+([0-9]+(?:\.[0-9]+)?)\s+([kmg]b)\b",
    re.I,
)


def normalize_label(label):
    label = label.lower()
    label = re.sub(r"\([^)]*\)", "", label)
    label = re.sub(r"[^a-z0-9]+", "_", label)
    return label.strip("_")


def memory_to_kb(value, unit):
    multipliers = {
        "kb": 1,
        "mb": 1024,
        "gb": 1024 * 1024,
    }
    return int(round(float(value) * multipliers[unit.lower()]))


def seconds_to_ms(value):
    return int(round(float(value) * 1000))


def strip_log_prefix(line):
    line = line.rstrip("\n")
    if line.startswith("#"):
        line = line[1:]
    return line.strip()


def source_for_path(path):
    return os.path.relpath(path, output_dir) if path.startswith(output_dir) else path


def add_entry(profile_mode, simulator, phase, current_kb, peak_kb, cpu_ms, source, line_number, **extra):
    key = (source, line_number, simulator, phase)
    if key in seen_sources:
        return
    seen_sources.add(key)
    entry = {
        "profile_mode": profile_mode,
        "simulator": simulator,
        "phase": phase,
        "current_memory_kb": current_kb,
        "peak_memory_kb": peak_kb,
        "simulation_cpu_ms": cpu_ms,
        "source": source,
        "line": line_number,
    }
    entry.update(extra)
    entries.append(entry)


def add_questa_entry(profile_mode, simulator, source, block):
    memory_metrics = block["memory_metrics_kb"]
    time_metrics = block["time_metrics_ms"]
    current_kb = None
    for label in (
        "size_during_sim",
        "size_after_elab",
        "size_of_process",
        "size_of_vopt_process",
    ):
        if label in memory_metrics:
            current_kb = memory_metrics[label]
            break
    if current_kb is None and memory_metrics:
        current_kb = max(memory_metrics.values())

    add_entry(
        profile_mode,
        simulator,
        block["phase"],
        current_kb,
        max(memory_metrics.values()) if memory_metrics else None,
        time_metrics.get("sim_cpu_time"),
        source,
        block["line"],
        simulation_wall_ms=time_metrics.get("sim_wall_time"),
        total_cpu_ms=time_metrics.get("total_cpu_time"),
        total_wall_ms=time_metrics.get("total_wall_time"),
        memory_metrics_kb=memory_metrics,
        time_metrics_ms=time_metrics,
        hdl_simulation_time=block.get("hdl_simulation_time"),
        elapsed_time=block.get("elapsed_time"),
    )


def host_path(path):
    if path.startswith("/artefacts/"):
        return os.path.join(output_dir, path[len("/artefacts/"):])
    if path == "/artefacts":
        return output_dir
    return path


def scan_log(path, profile_mode, simulator):
    try:
        with open(path, "r", errors="replace") as log_file:
            source = source_for_path(path)
            current_questa_tool = None
            questa_block = None
            verilator_block = None
            for line_number, line in enumerate(log_file, 1):
                stripped = strip_log_prefix(line)
                xsim_match = xsim_re.search(line)
                if xsim_match:
                    current_kb, peak_kb, cpu_ms = map(int, xsim_match.groups())
                    add_entry(
                        profile_mode,
                        simulator,
                        "simulation",
                        current_kb,
                        peak_kb,
                        cpu_ms,
                        source,
                        line_number,
                    )

                verilator_wall_match = verilator_wall_re.search(stripped)
                if verilator_wall_match:
                    verilator_block = {
                        "line": line_number,
                        "wall_ms": seconds_to_ms(verilator_wall_match.group(1)),
                    }
                    continue

                verilator_cpu_match = verilator_cpu_re.search(stripped)
                if verilator_cpu_match:
                    cpu_s, threads, memory, unit = verilator_cpu_match.groups()
                    memory_kb = memory_to_kb(memory, unit)
                    add_entry(
                        profile_mode,
                        "verilator",
                        "simulation",
                        memory_kb,
                        memory_kb,
                        seconds_to_ms(cpu_s),
                        source,
                        verilator_block["line"] if verilator_block else line_number,
                        simulation_wall_ms=verilator_block["wall_ms"] if verilator_block else None,
                        total_cpu_ms=seconds_to_ms(cpu_s),
                        total_wall_ms=verilator_block["wall_ms"] if verilator_block else None,
                        verilator_threads=int(threads),
                    )
                    verilator_block = None
                    continue

                tool_match = questa_tool_re.match(stripped)
                if tool_match and questa_stats_arg_re.search(stripped):
                    current_questa_tool = tool_match.group(1).lower()

                if stripped == "Memory Statistics":
                    questa_block = {
                        "phase": current_questa_tool or "unknown",
                        "line": line_number,
                        "memory_metrics_kb": {},
                        "time_metrics_ms": {},
                    }
                    continue

                if questa_block is None:
                    continue

                memory_match = questa_memory_re.search(stripped)
                if memory_match:
                    label, value, unit = memory_match.groups()
                    questa_block["memory_metrics_kb"][normalize_label(label)] = memory_to_kb(value, unit)
                    continue

                time_match = questa_time_re.search(stripped)
                if time_match:
                    section, label, value = time_match.groups()
                    metric = "{}_{}".format(section.lower(), normalize_label(label))
                    questa_block["time_metrics_ms"][metric] = seconds_to_ms(value)
                    continue

                hdl_match = hdl_time_re.search(stripped)
                if hdl_match:
                    questa_block["hdl_simulation_time"] = hdl_match.group(1).strip()
                    continue

                end_match = end_time_re.search(stripped)
                if end_match:
                    questa_block["elapsed_time"] = end_match.group(1)
                    add_questa_entry(profile_mode, simulator, source, questa_block)
                    questa_block = None

            if questa_block is not None:
                add_questa_entry(profile_mode, simulator, source, questa_block)
    except OSError:
        return


with open(log_path, "r", errors="replace") as log:
    for line_number, line in enumerate(log, 1):
        mode_match = mode_start_re.search(line)
        if mode_match:
            mode = mode_match.group(1)
            continue

        xsim_match = xsim_re.search(line)
        if xsim_match:
            current_kb, peak_kb, cpu_ms = map(int, xsim_match.groups())
            add_entry(mode, "xsim", "simulation", current_kb, peak_kb, cpu_ms, "test-log.txt", line_number)

tool_by_cwd = None
for candidate in ("vivado-tool-timing", "tool-timing"):
    path = os.path.join(output_dir, candidate, "tool-by-cwd.tsv")
    if os.path.exists(path):
        tool_by_cwd = path
        break

if tool_by_cwd:
    with open(tool_by_cwd, "r", errors="replace") as timing:
        header = timing.readline()
        for row in timing:
            fields = row.rstrip("\n").split("\t")
            if len(fields) < 3:
                continue
            profile_mode, cwd, tool = fields[:3]
            simulator_by_tool = {
                "xsim": "xsim",
                "vsim": "modelsim",
                "qrun": "qrun",
            }
            if runtime_stats_enabled:
                simulator_by_tool["verilator"] = "verilator"
            if tool not in simulator_by_tool:
                continue
            for run_log in sorted(glob.glob(os.path.join(host_path(cwd), "run*.log"))):
                scan_log(run_log, profile_mode, simulator_by_tool[tool])

summary = {}
for entry in entries:
    key = (entry["profile_mode"], entry["simulator"], entry["phase"])
    current = summary.setdefault(key, {
        "profile_mode": entry["profile_mode"],
        "simulator": entry["simulator"],
        "phase": entry["phase"],
        "count": 0,
        "total_simulation_cpu_ms": 0,
        "total_cpu_ms": 0,
        "total_wall_ms": 0,
        "max_peak_memory_kb": 0,
    })
    current["count"] += 1
    current["total_simulation_cpu_ms"] += entry.get("simulation_cpu_ms") or 0
    current["total_cpu_ms"] += entry.get("total_cpu_ms") or 0
    current["total_wall_ms"] += entry.get("total_wall_ms") or 0
    current["max_peak_memory_kb"] = max(
        current["max_peak_memory_kb"],
        entry.get("peak_memory_kb") or 0,
    )

with open(tsv_path, "w") as tsv:
    tsv.write(
        "profile_mode\tsimulator\tcurrent_memory_kb\tpeak_memory_kb\t"
        "simulation_cpu_ms\tsource\tline\tphase\tsimulation_wall_ms\t"
        "total_cpu_ms\ttotal_wall_ms\n"
    )
    for entry in entries:
        def value(name):
            val = entry.get(name)
            return "" if val is None else str(val)
        tsv.write(
            "{profile_mode}\t{simulator}\t{current_memory_kb}\t"
            "{peak_memory_kb}\t{simulation_cpu_ms}\t{source}\t{line}\t"
            "{phase}\t{simulation_wall_ms}\t{total_cpu_ms}\t{total_wall_ms}\n"
            .format(
                profile_mode=value("profile_mode"),
                simulator=value("simulator"),
                current_memory_kb=value("current_memory_kb"),
                peak_memory_kb=value("peak_memory_kb"),
                simulation_cpu_ms=value("simulation_cpu_ms"),
                source=value("source"),
                line=value("line"),
                phase=value("phase"),
                simulation_wall_ms=value("simulation_wall_ms"),
                total_cpu_ms=value("total_cpu_ms"),
                total_wall_ms=value("total_wall_ms"),
            )
        )

with open(json_path, "w") as jf:
    json.dump({
        "entries": entries,
        "summary": list(summary.values()),
    }, jf, indent=2, sort_keys=True)
    jf.write("\n")
PY

  echo "Wrote sim-runtime-stats.tsv/json ($(awk 'NR > 1 { count += 1 } END { print count + 0 }' "${tsv}") entries)"
}

if [ ! -f "${REPO_ROOT}/Setup.bsh" ]; then
  echo "ERROR: Setup.bsh not found. Run from the SVUnit repo root or set REPO_ROOT." >&2
  exit 2
fi

# ---------------------------------------------------------------------------
# Adapter pre-validation (before we create any artefacts)
# ---------------------------------------------------------------------------
case "${TARGET_ADAPTER}" in
  container)
    for lic in quartus_license.dat questa_license.dat; do
      if [ ! -f "${LICENSE_DIR}/${lic}" ]; then
        echo "ERROR: Missing ${LICENSE_DIR}/${lic}" >&2
        exit 2
      fi
    done
    if ! "${CONTAINER_RUNTIME}" image exists "${TARGET_IMAGE}" >/dev/null 2>&1; then
      echo "ERROR: Container image ${TARGET_IMAGE} not found." >&2
      echo "Build it via the upstream Quartus Pro podman flake first." >&2
      exit 2
    fi
    ;;
  native)
    if ! command -v verilator >/dev/null 2>&1; then
      echo "ERROR: verilator binary not found on PATH." >&2
      exit 2
    fi
    VERILATOR_VERSION_OUT="$(verilator --version 2>&1)"
    if ! printf '%s\n' "${VERILATOR_VERSION_OUT}" | grep -qF "${TARGET_EXPECTED_VERILATOR}"; then
      echo "ERROR: verilator version mismatch - expected ${TARGET_EXPECTED_VERILATOR}, got ${VERILATOR_VERSION_OUT}" >&2
      exit 2
    fi
    for bin in gcc make; do
      if ! command -v "$bin" >/dev/null 2>&1; then
        echo "ERROR: $bin not found on PATH (required for Verilator compilation)." >&2
        exit 2
      fi
    done
