setup_tool_timing_wrappers() {
  local timing_dir="$1"
  shift

  local wrapper_bin="${timing_dir}/bin"
  local timing_log="${timing_dir}/tool-invocations.tsv"
  mkdir -p "${wrapper_bin}"
  printf 'start_utc\ttool\tduration_ms\texit_code\tcwd\targs\tprofile_mode\tend_utc\tstart_epoch_ms\tend_epoch_ms\tpid\n' > "${timing_log}"

  local tool real_tool wrapper
  for tool in "$@"; do
    real_tool="$(command -v "$tool" 2>/dev/null || true)"
    if [ -z "${real_tool}" ]; then
      continue
    fi
    wrapper="${wrapper_bin}/${tool}"
    {
      printf '#!/usr/bin/env bash\n'
      printf 'set -uo pipefail\n'
      printf 'real_tool=%q\n' "${real_tool}"
      printf 'tool_name=%q\n' "${tool}"
      printf 'timing_log=%q\n' "${timing_log}"
      cat <<'WRAP_EOF'
start_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
start_ns="$(date +%s%N)"
start_epoch_ms=$(( start_ns / 1000000 ))
pid="${BASHPID:-$$}"
"${real_tool}" "$@"
rc=$?
end_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
end_ns="$(date +%s%N)"
end_epoch_ms=$(( end_ns / 1000000 ))
duration_ms=$(( (end_ns - start_ns) / 1000000 ))
args=()
for arg in "$@"; do
  args+=("$(printf '%q' "$arg")")
done
printf '%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\t%s\n' \
  "$start_utc" "$tool_name" "$duration_ms" "$rc" "$PWD" "${args[*]}" \
  "${SVUNIT_PROFILE_MODE:-unknown}" "$end_utc" "$start_epoch_ms" \
  "$end_epoch_ms" "$pid" \
  >> "$timing_log"
exit "$rc"
WRAP_EOF
    } > "${wrapper}"
    chmod +x "${wrapper}"
  done

  export PATH="${wrapper_bin}:${PATH}"
}

write_tool_timing_summary() {
  local timing_dir="$1"
  local timing_log="${timing_dir}/tool-invocations.tsv"

  [ -f "${timing_log}" ] || return 0

  awk -F '\t' '
    BEGIN {
      OFS = "\t"
      print "profile_mode", "tool", "count", "total_ms", "avg_ms", "max_ms"
    }
    NR > 1 {
      duration_ms = $3 + 0
      key = $7 SUBSEP $2
      if (!(key in seen)) {
        seen[key] = 1
        keys[++n] = key
        profile_mode[key] = $7
        tool[key] = $2
      }
      count[key] += 1
      total_ms[key] += duration_ms
      if (duration_ms > max_ms[key]) {
        max_ms[key] = duration_ms
      }
    }
    END {
      for (i = 1; i <= n; i++) {
        key = keys[i]
        avg_ms = count[key] ? total_ms[key] / count[key] : 0
        printf "%s\t%s\t%d\t%.0f\t%.1f\t%.0f\n",
          profile_mode[key], tool[key], count[key], total_ms[key], avg_ms, max_ms[key]
      }
    }
  ' "${timing_log}" > "${timing_dir}/tool-summary.tsv"

  awk -F '\t' '
    BEGIN {
      OFS = "\t"
      print "profile_mode", "cwd", "tool", "count", "total_ms", "avg_ms", "max_ms"
    }
    NR > 1 {
      duration_ms = $3 + 0
      key = $7 SUBSEP $5 SUBSEP $2
      if (!(key in seen)) {
        seen[key] = 1
        keys[++n] = key
        profile_mode[key] = $7
        cwd[key] = $5
        tool[key] = $2
      }
      count[key] += 1
      total_ms[key] += duration_ms
      if (duration_ms > max_ms[key]) {
        max_ms[key] = duration_ms
      }
    }
    END {
      for (i = 1; i <= n; i++) {
        key = keys[i]
        avg_ms = count[key] ? total_ms[key] / count[key] : 0
        printf "%s\t%s\t%s\t%d\t%.0f\t%.1f\t%.0f\n",
          profile_mode[key], cwd[key], tool[key], count[key], total_ms[key], avg_ms, max_ms[key]
      }
    }
  ' "${timing_log}" > "${timing_dir}/tool-by-cwd.tsv"

  echo "Wrote tool timing summaries in ${timing_dir}"
}

run_profile_pytest() {
  local mode="$1"
  local filter="$2"
  local xml="$3"
  local start_utc start_ns end_utc end_ns duration_ms pytest_rc

  echo ""
  start_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
  start_ns="$(date +%s%N)"
  echo "--- pytest ${mode} -k ${filter} start=${start_utc} ---"
  set +e
  SVUNIT_PROFILE_MODE="${mode}" \
    SVUNIT_REUSE_BUILD="${REUSE_BUILD}" \
    SVUNIT_XSIM_REUSE_BUILD="${XSIM_REUSE_BUILD:-0}" \
    SVUNIT_SIM_DEBUG_LEVEL="${SIM_DEBUG_LEVEL:-}" \
    SVUNIT_SIM_RUNTIME_STATS="${SIM_RUNTIME_STATS:-0}" \
    SVUNIT_XSIM_RUN_MODE="${XSIM_RUN_MODE:-}" \
    python3 -m pytest -v -k "${filter}" \
    --tb=short \
    --basetemp="/artefacts/pytest-${mode}" \
    --durations=0 \
    --junitxml="${xml}" \
    2>&1
  pytest_rc=$?
  set -e
  end_utc="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
  end_ns="$(date +%s%N)"
  duration_ms=$(( (end_ns - start_ns) / 1000000 ))
  echo "--- pytest ${mode} end=${end_utc} duration_ms=${duration_ms} exit_code=${pytest_rc} ---"
}

