)

# Guard: every adapter must write JQ output to TMP_JSON before the mv below,
# otherwise the good JSON qh_build_info_json just wrote gets clobbered by an
# empty file.  An unhandled adapter is a programming error - abort, don't
# silently corrupt artefacts.
case "${TARGET_ADAPTER}" in
  container)
    # Sim-only images report "N/A (sim-only)" rather than an empty string
    # so downstream consumers can distinguish absent-by-design from missing-value.
    QUARTUS_VERSION_REPORTED="${TARGET_EXPECTED_QUARTUS:-N/A (sim-only)}"
    jq "${JQ_COMMON[@]}" \
      --arg image_tag "${TARGET_IMAGE}" \
      --arg image_id "${IMAGE_ID}" \
      --arg quartus_version "${QUARTUS_VERSION_REPORTED}" \
      --arg questa_version "${TARGET_EXPECTED_QUESTA}" \
      '. + {
        target: $target, simulator: $sim, simulator_display: $sim_display,
        container_image_tag: $image_tag, container_image_id: $image_id,
        quartus_version: $quartus_version, questa_version: $questa_version,
        svunit_commit: $svunit_commit, pytest_filter: $pytest_filter,
        sim_debug_level: $sim_debug_level,
        xsim_run_mode: $xsim_run_mode,
        per_fixture_pytest_filter: $per_fixture_pytest_filter,
        compile_once_pytest_filter: $compile_once_pytest_filter,
        reuse_build: $reuse_build,
        xsim_reuse_build: $xsim_reuse_build,
        sim_runtime_stats: $sim_runtime_stats,
        qualification_status: $status,
        tests_total: $tests_total, tests_passed: $tests_passed,
        tests_failed: $tests_failed, tests_errors: $tests_errors,
        tests_skipped: $tests_skipped,
        per_fixture_tests_total: $per_fixture_tests_total,
        per_fixture_tests_passed: $per_fixture_tests_passed,
        per_fixture_tests_failed: $per_fixture_tests_failed,
        per_fixture_tests_errors: $per_fixture_tests_errors,
        per_fixture_tests_skipped: $per_fixture_tests_skipped,
        compile_once_tests_total: $compile_once_tests_total,
        compile_once_tests_passed: $compile_once_tests_passed,
        compile_once_tests_failed: $compile_once_tests_failed,
        compile_once_tests_errors: $compile_once_tests_errors,
        compile_once_tests_skipped: $compile_once_tests_skipped,
        exit_code: $exit_code
      }' "${OUTPUT_DIR}/build-info.json" > "${TMP_JSON}"
    ;;
  native)
    jq "${JQ_COMMON[@]}" \
      --arg verilator_version "${TARGET_EXPECTED_VERILATOR}" \
      --arg verilator_store_path "${TARGET_VERILATOR_STORE_PATH}" \
      '. + {
        target: $target, simulator: $sim, simulator_display: $sim_display,
        verilator_version: $verilator_version,
        verilator_store_path: $verilator_store_path,
        svunit_commit: $svunit_commit, pytest_filter: $pytest_filter,
        sim_debug_level: $sim_debug_level,
        xsim_run_mode: $xsim_run_mode,
        per_fixture_pytest_filter: $per_fixture_pytest_filter,
        compile_once_pytest_filter: $compile_once_pytest_filter,
        reuse_build: $reuse_build,
        xsim_reuse_build: $xsim_reuse_build,
        sim_runtime_stats: $sim_runtime_stats,
        qualification_status: $status,
        tests_total: $tests_total, tests_passed: $tests_passed,
        tests_failed: $tests_failed, tests_errors: $tests_errors,
        tests_skipped: $tests_skipped,
        per_fixture_tests_total: $per_fixture_tests_total,
        per_fixture_tests_passed: $per_fixture_tests_passed,
        per_fixture_tests_failed: $per_fixture_tests_failed,
        per_fixture_tests_errors: $per_fixture_tests_errors,
        per_fixture_tests_skipped: $per_fixture_tests_skipped,
        compile_once_tests_total: $compile_once_tests_total,
        compile_once_tests_passed: $compile_once_tests_passed,
        compile_once_tests_failed: $compile_once_tests_failed,
        compile_once_tests_errors: $compile_once_tests_errors,
        compile_once_tests_skipped: $compile_once_tests_skipped,
        exit_code: $exit_code
      }' "${OUTPUT_DIR}/build-info.json" > "${TMP_JSON}"
    ;;
  fhs)
    VIVADO_IS_STUB_JSON=false
    if [ "${TARGET_VIVADO_IS_STUB}" = "1" ]; then
      VIVADO_IS_STUB_JSON=true
    fi
    jq "${JQ_COMMON[@]}" \
      --arg vivado_version "${TARGET_EXPECTED_VIVADO}" \
      --arg vivado_profile "${TARGET_VIVADO_PROFILE}" \
      --arg vivado_store_path "${TARGET_VIVADO_STORE_PATH}" \
      --arg vivado_qualified_root "${TARGET_QUALIFIED_ROOT}" \
      --argjson vivado_is_stub "${VIVADO_IS_STUB_JSON}" \
      '. + {
        target: $target, simulator: $sim, simulator_display: $sim_display,
        vivado_version: $vivado_version,
        vivado_profile: $vivado_profile,
        vivado_store_path: $vivado_store_path,
        vivado_qualified_root: $vivado_qualified_root,
        vivado_is_stub: $vivado_is_stub,
        svunit_commit: $svunit_commit, pytest_filter: $pytest_filter,
        sim_debug_level: $sim_debug_level,
        xsim_run_mode: $xsim_run_mode,
        per_fixture_pytest_filter: $per_fixture_pytest_filter,
        compile_once_pytest_filter: $compile_once_pytest_filter,
        reuse_build: $reuse_build,
        xsim_reuse_build: $xsim_reuse_build,
        sim_runtime_stats: $sim_runtime_stats,
        qualification_status: $status,
        tests_total: $tests_total, tests_passed: $tests_passed,
        tests_failed: $tests_failed, tests_errors: $tests_errors,
        tests_skipped: $tests_skipped,
        per_fixture_tests_total: $per_fixture_tests_total,
        per_fixture_tests_passed: $per_fixture_tests_passed,
        per_fixture_tests_failed: $per_fixture_tests_failed,
        per_fixture_tests_errors: $per_fixture_tests_errors,
        per_fixture_tests_skipped: $per_fixture_tests_skipped,
        compile_once_tests_total: $compile_once_tests_total,
        compile_once_tests_passed: $compile_once_tests_passed,
        compile_once_tests_failed: $compile_once_tests_failed,
        compile_once_tests_errors: $compile_once_tests_errors,
        compile_once_tests_skipped: $compile_once_tests_skipped,
        exit_code: $exit_code
      }' "${OUTPUT_DIR}/build-info.json" > "${TMP_JSON}"
    ;;
  *)
    echo "ERROR: build-info.json JSON stage not implemented for adapter '${TARGET_ADAPTER}'" >&2
    rm -f "${TMP_JSON}"
    exit 2
    ;;
esac
mv "${TMP_JSON}" "${OUTPUT_DIR}/build-info.json"

# ---------------------------------------------------------------------------
# qualification-results.md
# ---------------------------------------------------------------------------
OS_VER="$(grep '^VERSION_ID=' /etc/os-release 2>/dev/null | cut -d= -f2 | tr -d '"' || echo unknown)"
NIX_VER="$(nix --version 2>/dev/null | awk '{print $NF}' || echo unknown)"
KERNEL_VER="$(uname -r)"

{
  cat <<QREOF
# Qualification Results - ${TOOL_GROUP} ${TOOL_VERSION}

**Target:** ${TARGET_NAME}
**Run ID:** ${QH_RUN_ID}
**Pass:** generic
**Executed:** $(date -u +"%Y-%m-%dT%H:%M:%SZ")
**Overall:** ${STATUS} (${PASSED} passed, ${FAILURES} failed, ${SKIPPED} skipped)

## Environment

| Field | Value |
|-------|-------|
| OS | NixOS ${OS_VER} |
| Kernel | ${KERNEL_VER} |
| Nix | ${NIX_VER} |
| Platform | x86_64-linux |
| Hostname | $(hostname) |
QREOF

  case "${TARGET_ADAPTER}" in
    container)
      cat <<SIMEOF

## Simulator

| Field | Value |
|-------|-------|
| Target | ${TARGET_NAME} |
| Simulator | ${TARGET_TOOL} |
| Description | ${TARGET_DISPLAY_NAME} |
| Container Image | ${TARGET_IMAGE} |
| Container Image ID | ${IMAGE_ID} |
| Quartus Version | ${TARGET_EXPECTED_QUARTUS:-N/A (sim-only)} |
| Questa Version | ${TARGET_EXPECTED_QUESTA} |
SIMEOF
      ;;
    native)
      cat <<SIMEOF

## Simulator

| Field | Value |
|-------|-------|
| Target | ${TARGET_NAME} |
| Simulator | ${TARGET_TOOL} |
| Description | ${TARGET_DISPLAY_NAME} |
| Verilator Version | ${TARGET_EXPECTED_VERILATOR} |
| Verilator Store Path | ${TARGET_VERILATOR_STORE_PATH} |
| Container | None (native execution) |
SIMEOF
      ;;
    fhs)
      cat <<SIMEOF

## Simulator

| Field | Value |
|-------|-------|
| Target | ${TARGET_NAME} |
| Simulator | ${TARGET_TOOL} |
| Description | ${TARGET_DISPLAY_NAME} |
| Vivado Version | ${TARGET_EXPECTED_VIVADO} |
| Vivado Profile | ${TARGET_VIVADO_PROFILE} |
| Vivado Store Path | ${TARGET_VIVADO_STORE_PATH} |
| Qualified Root | ${TARGET_QUALIFIED_ROOT} |
| Container | None (native buildFHSEnv wrappers) |
SIMEOF
      ;;
    *)
      # Guard: unhandled adapter would leave the markdown without its
      # Simulator section, breaking the qualification standard's layout.
      echo "ERROR: qualification-results.md Simulator section not implemented for adapter '${TARGET_ADAPTER}'" >&2
      exit 2
      ;;
  esac

  cat <<TAILEOF

## SVUnit

| Field | Value |
|-------|-------|
| Qualified Version | ${QUALIFIED_VERSION} |
| Commit | ${SVUNIT_COMMIT} |
| Base Pytest Filter | ${PYTEST_FILTER} |
| Simulator Debug Level | ${SIM_DEBUG_LEVEL:-default} |
| xsim Run Mode | ${XSIM_RUN_MODE:-separate} |
| Per-Fixture Pytest Filter | ${PER_FIXTURE_PYTEST_FILTER} |
| Compile-Once Pytest Filter | ${COMPILE_ONCE_PYTEST_FILTER} |
| Reuse Build | ${REUSE_BUILD} |
| Simulator Runtime Stats | ${SIM_RUNTIME_STATS} |

## Test Summary

| Metric | Count |
|--------|-------|
| Total | ${TOTAL} |
| Passed | ${PASSED} |
| Failed | ${FAILURES} |
| Errors | ${ERRORS} |
| Skipped | ${SKIPPED} |

## Regression Modes

| Mode | Total | Passed | Failed | Errors | Skipped | Purpose |
|------|------:|-------:|-------:|-------:|--------:|---------|
| per-fixture | ${PER_FIXTURE_TOTAL} | ${PER_FIXTURE_PASSED} | ${PER_FIXTURE_FAILURES} | ${PER_FIXTURE_ERRORS} | ${PER_FIXTURE_SKIPPED} | Final-regression style: pytest fixture isolation, with a fresh SVUnit build/compile/run per fixture. |
| compile-once | ${COMPILE_ONCE_TOTAL} | ${COMPILE_ONCE_PASSED} | ${COMPILE_ONCE_FAILURES} | ${COMPILE_ONCE_ERRORS} | ${COMPILE_ONCE_SKIPPED} | Developer-iteration style: one SVUnit build compiles multiple suites in a single workspace and runs them together. |

## Evidence

- tests.xml - compatibility copy of the per-fixture JUnit XML results.
- tests-per-fixture.xml - JUnit XML results from the per-fixture regression.
- tests-compile-once.xml - JUnit XML results from the compile-once multi-fixture regression.
- test-log.txt - full output including version checks and both pytest outputs.
- build-info.json - machine-readable qualification metadata.
- timing-summary.json - per-fixture per-test durations for cross-simulator profiling.
- timing-summary-compile-once.json - compile-once per-test durations for cross-simulator profiling.
- sim-runtime-stats.tsv - parsed simulator runtime statistics from retained pytest run logs when enabled.
- sim-runtime-stats.json - machine-readable simulator runtime statistics summary.
- pytest-per-fixture/ and pytest-compile-once/ - retained pytest workspaces, including simulator run logs used for runtime-stat parsing.
TAILEOF

  if [ "${TARGET_ADAPTER}" = "container" ]; then
    echo "- image-inspect.json - container image metadata."
    echo "- tool-timing/tool-invocations.tsv - per-process simulator/tool timings tagged by regression mode, with start/end timestamps."
    echo "- tool-timing/tool-summary.tsv - simulator/tool timing totals by regression mode and tool."
    echo "- tool-timing/tool-by-cwd.tsv - simulator/tool timing totals by regression mode, workspace, and tool."
  fi
  if [ "${TARGET_ADAPTER}" = "native" ]; then
    echo "- tool-timing/tool-invocations.tsv - per-process Verilator/toolchain timings tagged by regression mode, with start/end timestamps."
    echo "- tool-timing/tool-summary.tsv - Verilator/toolchain timing totals by regression mode and tool."
    echo "- tool-timing/tool-by-cwd.tsv - Verilator/toolchain timing totals by regression mode, workspace, and tool."
  fi
  if [ "${TARGET_ADAPTER}" = "fhs" ]; then
    echo "- vivado-smoke/ - direct Vivado package smoke logs for vivado, xvlog, xelab, and xsim."
    echo "- vivado-tool-timing/tool-invocations.tsv - per-process Vivado tool timings tagged by regression mode, including FHS wrapper startup, with start/end timestamps."
    echo "- vivado-tool-timing/tool-summary.tsv - Vivado timing totals by regression mode and tool."
    echo "- vivado-tool-timing/tool-by-cwd.tsv - Vivado timing totals by regression mode, workspace, and tool."
  fi

  # Reference the raw log rather than inlining it.  Inlining inside a fenced
  # code block is hazardous: any pytest/tool output line containing three or
  # more consecutive backticks prematurely terminates the outer fence and
  # corrupts the evidence artefact layout (WR-01).  The file is already
  # listed in the Evidence section above, so linking is sufficient and
  # avoids doubling storage.
  cat <<'RAWEOF'

## Raw Output

See `test-log.txt` in this directory for the full unmodified output.
RAWEOF
} > "${OUTPUT_DIR}/qualification-results.md"

# ---------------------------------------------------------------------------
# Update latest symlink and print summary
# ---------------------------------------------------------------------------
qh_update_latest_symlink "${ARTEFACTS_ROOT}" "${QH_RUN_ID}"

echo ""
echo "=== Qualification Complete ==="
echo "Target:   ${TARGET_NAME}"
echo "Status:   ${STATUS}"
echo "Results:  ${PASSED} passed, ${FAILURES} failed, ${ERRORS} errors, ${SKIPPED} skipped (of ${TOTAL})"
echo "Modes:    per-fixture ${PER_FIXTURE_PASSED} passed/${PER_FIXTURE_FAILURES} failed/${PER_FIXTURE_ERRORS} errors/${PER_FIXTURE_SKIPPED} skipped; compile-once ${COMPILE_ONCE_PASSED} passed/${COMPILE_ONCE_FAILURES} failed/${COMPILE_ONCE_ERRORS} errors/${COMPILE_ONCE_SKIPPED} skipped"
echo "Run ID:   ${QH_RUN_ID}"
echo "Output:   ${OUTPUT_DIR}"

if [ "${STATUS}" = "FAIL" ]; then
  exit 1
fi
